#include <bits/stdc++.h>
using namespace std;
int main(){
    int n; cin >> n;
    vector<int> arr(n);
    for(int i = 0; i < n; i++) cin >> arr[i];
    stack<int> st;
    long long res = 0;
    for(int i = 0; i < n; i++){
        while(!st.empty() && arr[st.top()] >= arr[i]){
            int mid = st.top(); st.pop();
            int left = st.empty() ? -1 : st.top();
            int right = i;
            res += (long long)arr[mid] * (mid - left) * (right - mid);
        }
        st.push(i);
    }
    while(!st.empty()){
        int mid = st.top(); st.pop();
        int left = st.empty() ? -1 : st.top();
        int right = n;
        res += (long long)arr[mid] * (mid - left) * (right - mid);
    }
    cout << res << '\n';
}
